/**
 * Diff Review Panel - Webview Script
 * Handles diff rendering and comment interactions using diff2html
 */
(function() {
  'use strict';

  // Get VSCode API
  const vscode = acquireVsCodeApi();

  // State
  let currentData = null;
  let comments = [];

  // Restore previous state if available
  const previousState = vscode.getState();
  if (previousState) {
    currentData = previousState.currentData || null;
    comments = previousState.comments || [];
  }

  /**
   * Save current state for persistence
   */
  function saveState() {
    vscode.setState({
      currentData,
      comments,
      scrollPosition: window.scrollY
    });
  }

  // Notify extension we're ready
  vscode.postMessage({ type: 'ready' });

  // Handle messages from extension
  window.addEventListener('message', event => {
    const message = event.data;

    switch (message.type) {
      case 'loadDiff':
        currentData = message.data;
        renderDiff(message.data);
        saveState();
        break;
      case 'themeChanged':
        updateTheme(message.theme);
        break;
      case 'updateComments':
        comments = message.comments || [];
        renderComments(comments);
        saveState();
        break;
    }
  });

  // Restore scroll position after content loads
  if (previousState && previousState.scrollPosition) {
    requestAnimationFrame(() => {
      window.scrollTo(0, previousState.scrollPosition);
    });
  }

  /**
   * Render the diff content using diff2html
   */
  function renderDiff(data) {
    const container = document.getElementById('diff-container');

    if (!data.unifiedDiff || data.unifiedDiff.trim() === '') {
      container.innerHTML = `
        <div class="empty-state">
          <div class="icon">📄</div>
          <p>No changes to display</p>
        </div>
      `;
      updateStats(0, 0);
      return;
    }

    // Check if diff2html is available
    if (typeof Diff2Html === 'undefined') {
      container.innerHTML = `
        <div class="error-state">
          <p>Error: diff2html library not loaded</p>
        </div>
      `;
      return;
    }

    // Use diff2html to render
    const diffHtml = Diff2Html.html(data.unifiedDiff, {
      drawFileList: false,
      matching: 'lines',
      outputFormat: 'side-by-side',
      renderNothingWhenEmpty: false
    });

    container.innerHTML = diffHtml;

    // Calculate and update stats
    const additions = (data.unifiedDiff.match(/^\+[^+]/gm) || []).length;
    const deletions = (data.unifiedDiff.match(/^-[^-]/gm) || []).length;
    updateStats(additions, deletions);

    // Setup line hover handlers for comments (WI-05)
    setupLineHandlers();

    // Apply current theme
    const isDark = document.body.classList.contains('vscode-dark') ||
                   document.body.classList.contains('dark');
    if (isDark) {
      container.classList.add('d2h-dark-color-scheme');
    }
  }

  /**
   * Update stats display
   */
  function updateStats(additions, deletions) {
    const statsEl = document.getElementById('stats');
    if (statsEl) {
      statsEl.innerHTML = `<span class="additions">+${additions}</span> <span class="deletions">-${deletions}</span>`;
    }
  }

  /**
   * Setup line click handlers for adding comments
   * Will be fully implemented in WI-05
   */
  function setupLineHandlers() {
    const lineNumbers = document.querySelectorAll('.d2h-code-linenumber');
    lineNumbers.forEach(lineNum => {
      lineNum.style.cursor = 'pointer';
      lineNum.addEventListener('click', handleLineClick);
    });
  }

  /**
   * Handle line click for adding comment
   * Placeholder - will be implemented in WI-05
   */
  function handleLineClick(event) {
    const lineNum = event.target.closest('.d2h-code-linenumber');
    if (!lineNum) return;

    const lineNumber = lineNum.textContent.trim();
    console.log('Line clicked:', lineNumber);
    // Will trigger comment creation in WI-05
  }

  /**
   * Update the theme class on body
   */
  function updateTheme(theme) {
    document.body.className = theme;
    const container = document.getElementById('diff-container');
    if (theme === 'dark') {
      container.classList.add('d2h-dark-color-scheme');
    } else {
      container.classList.remove('d2h-dark-color-scheme');
    }
  }

  /**
   * Render comments
   * Placeholder implementation - full UI in WI-05
   */
  function renderComments(comments) {
    // Will be implemented in WI-05
    console.log('Comments to render:', comments);
  }

  /**
   * Escape HTML special characters
   */
  function escapeHtml(text) {
    if (!text) return '';
    const div = document.createElement('div');
    div.textContent = text;
    return div.innerHTML;
  }

  /**
   * Post a message to the extension
   */
  function postMessage(type, data) {
    vscode.postMessage({ type, ...data });
  }

  // Expose functions for future use
  window.diffReview = {
    postMessage,
    renderDiff,
    renderComments,
    saveState
  };

  // Render cached data if available (for restored sessions)
  if (previousState && previousState.currentData) {
    renderDiff(previousState.currentData);
    if (previousState.comments && previousState.comments.length > 0) {
      renderComments(previousState.comments);
    }
  }
})();

